import{_ as e,o as t,c as b,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"人皇步","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/防御类/人皇步.md","filePath":"4.资源分区/6.技艺及称号/防御类/人皇步.md"}'),o={name:"4.资源分区/6.技艺及称号/防御类/人皇步.md"};function d(p,a,l,_,i,c){return t(),b("div",null,[...a[0]||(a[0]=[r("h1",{id:"人皇步",tabindex:"-1"},[s("人皇步 "),r("a",{class:"header-anchor",href:"#人皇步","aria-label":'Permalink to "人皇步"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),n('<h1 id="人皇步-1" tabindex="-1">人皇步 <a class="header-anchor" href="#人皇步-1" aria-label="Permalink to &quot;人皇步&quot;">​</a></h1><p>人皇步<br> C+1750<br> 一个诡异的小镇，几个大衣黑帽的调查员，人人脸上只有冷漠和麻木，但在不远处，一个破旧的小木屋突兀滴出现在地面。<br> 其中一个队员突然间扭曲肢体，跳起了诡异的舞蹈……是DJ舞蹈！<br> 该死他也被影响了吗？队长这样想着，直到这个人开口唱出<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。<br> 。</p><p>妙妙屋！卧槽，太好了，我们走！哟嘿，差点忘了，要让妙妙屋出现，我们得说点小JB话！<br> 密斯卡，莫斯卡！<br> 密斯卡，莫斯卡！<br> 芜湖！米老鼠！<br> ……<br> 无论如何，这个技艺效果只能持续一个场景。</p><p>【密斯卡！】你可以以一个标准动作唱出密斯卡！接下来你的移速不会提升……在别人视角里，你不再是正常移动，而是如同在平面一样滑动，但因此你必须时刻在刀尖跳舞，同时你围绕移动的目标因为歌唱吵闹，只想一刀攮死你，以你为中心，15米半径内的区域将产生一个C级困难地形，处于困难地形中的角色还会受到特异来源的C级胁迫效果，你将无法通过不是基础移动的方式离开，战斗中最危险的敌人10米周围，如果脱离该范围，该技艺所有加值和效果将失效。</p><p>【莫斯卡！】当你唱出密斯卡，下一句必定是莫斯卡！因为你无时无刻不在移动跳舞，此时你获得相当于敏捷属性/2+敏捷附加*1的闪避防御，同时你的双臂也开始摇摆，腿也不自觉开始抖动……先上DJ！嗨起来！同样的，你成为战场中最靓的风景线的时候，一样无法攻击别人。在该技艺持续时间内，你无法攻击敌人，一旦停下攻击敌人，该技艺将失去所有加值和效果。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',7)])])}const f=e(o,[["render",d]]);export{m as __pageData,f as default};
